const isCallback = Boolean($json.callback_query);

const callback = $json.callback_query || null;
const message = isCallback
  ? (callback.message || {})
  : ($json.message || {});

const text = isCallback
  ? String(callback.data || '').trim()
  : String(message.text || '').trim();

const inputType = isCallback ? 'callback'
  : message.voice ? 'voice'
  : message.photo ? 'image'
  : message.document ? 'document'
  : 'text';

// КРИТИЧЕСКИЙ ФИКС:
// Для обычных сообщений используем message_id.
// Для callback используем callback.id, потому что message.message_id у кнопки повторяется.
const externalMessageId = isCallback
  ? 'callback:' + String(callback.id || '')
  : 'message:' + String(message.message_id || '');

return [{
  json: {
    execution_id: $execution.id + '_' + Date.now(),
    source: 'telegram',
    input_type: inputType,

    // Это поле дальше уходит в intake_events.external_message_id
    message_id: externalMessageId,

    chat_id: message.chat?.id || null,
    user_id: isCallback ? (callback.from?.id || null) : (message.from?.id || null),

    text,
    callback_data: isCallback ? text : null,
    is_callback: isCallback,
    is_command: !isCallback && text.startsWith('/'),

    raw: $json
  }
}];

const ctx = $('Init execution context').first().json;

return [{
  json: {
    ...ctx,
    intake_event_id: $json.id || null,
    intake_status: $json.status || null
  }
}];

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: String($json.chat_id),
    response_message_type: 'help',
    response_body:
`📄 Как отправить резюме

Можно прислать:
• текст обычным сообщением
• PDF или DOCX
• фото резюме
• голосовое сообщение

Я приведу данные к тексту, извлеку профиль кандидата и сравню его с открытыми вакансиями.`
  }
}];

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: String($json.chat_id),
    response_message_type: 'about',
    response_body:
`💼 О проекте

Это мультимодальный HR-ассистент.

Он принимает резюме в разных форматах, приводит их к единому виду, анализирует данные кандидата и подбирает наиболее подходящую вакансию.`
  }
}];

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: String($json.chat_id),
    response_message_type: 'restart',
    response_body:
`📄 Готов принять новое резюме.

Отправьте его текстом, файлом PDF/DOCX, фото или голосовым сообщением.`
  }
}];

const command = ($json.text || '').trim();

let body;
let telegram_reply_markup = null;

if (command === '/start') {
  body =
    'Привет! Я HR-ассистент 🤖\n\n' +
    'Отправьте резюме любым удобным способом:\n' +
    '• текстом\n' +
    '• PDF / DOCX\n' +
    '• фото\n' +
    '• голосовым сообщением\n\n' +
    'Я извлеку данные кандидата и подберу подходящую вакансию.';

  telegram_reply_markup = {
    inline_keyboard: [
      [
        { text: '📄 Как отправить резюме', callback_data: 'help' }
      ],
      [
        { text: '💼 О проекте', callback_data: 'about' }
      ]
    ]
  };
} else if (command === '/help') {
  body =
    '📄 Как пользоваться HR-ассистентом:\n\n' +
    '1. Пришлите резюме текстом, PDF/DOCX, фото или голосом.\n' +
    '2. Я извлеку ФИО, город, должность, опыт, навыки, контакты и зарплатные ожидания.\n' +
    '3. Затем сравню кандидата с открытыми вакансиями.\n' +
    '4. В ответе верну подходящую вакансию или сообщение, что подходящей позиции пока нет.';
} else {
  body =
    'Команда получена. Для проверки пришлите резюме обычным сообщением, файлом PDF/DOCX, фото или голосом.';
}

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: $json.chat_id ? String($json.chat_id) : null,
    response_message_type: 'command',
    response_subject: null,
    response_body: body,
    telegram_reply_markup
  }
}];

const ctx = $('Build context after intake insert').first().json;

return [{
  json: {
    ...ctx,
    candidate_input_id: $json.id
  }
}];

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: $json.chat_id ? String($json.chat_id) : null,
    response_message_type: 'accepted',
    response_subject: null,
    response_body: '📥 Резюме получено\n\n⏳ Начинаю анализ...'
  }
}];

const item = $input.first();

return [{
  json: item.json,
  binary: {
    data: {
      ...item.binary.data,
      fileName: 'voice.ogg',
      mimeType: 'audio/ogg',
      fileExtension: 'ogg'
    }
  }
}];

const ctx = $('Build context after intake insert').first().json;

const sttText =
  $json.text ||
  $json.transcription ||
  $json.result ||
  '';

return [{
  json: {
    ...ctx,
    input_type: 'voice',
    text: String(sttText).trim(),
    normalized_text: String(sttText).trim(),
    stt_provider: 'openai',
    stt_status: String(sttText).trim() ? 'success' : 'empty'
  }
}];

const ctx = $('Build context after intake insert').first().json || {};
const err = $json.error || $json;
const technicalMessage = err.message || err.description || err.error || 'Voice transcription failed or returned empty text';

return [{
  json: {
    ...ctx,
    error_stage: 'intake',
    error_type: 'stt_error',
    error_message: String(technicalMessage || 'Voice transcription failed or returned empty text'),
    error_recoverable: true,
    response_channel: 'telegram',
    response_recipient: ctx.chat_id ? String(ctx.chat_id) : null,
    response_message_type: 'voice_stt_error',
    response_subject: null,
    response_body:
`⚠️ Не удалось распознать голосовое сообщение

Попробуйте:
• сказать чётче
• записать короче
• отправить резюме текстом или PDF/DOCX`
  }
}];

const input = $input.first();
const ctx = $('Build context after intake insert').first().json;

const binary = input.binary || {};
const file = binary.data || {};

const fileName =
  file.fileName ||
  input.json.raw?.message?.document?.file_name ||
  'document';

const mimeType =
  file.mimeType ||
  input.json.raw?.message?.document?.mime_type ||
  '';

const ext = (fileName.split('.').pop() || '').toLowerCase();
const isPdf = ext === 'pdf' || mimeType === 'application/pdf';
const isDocx = ext === 'docx' || mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';

return [{
  json: {
    ...ctx,
    input_type: 'document',
    document_file_name: fileName,
    document_mime_type: mimeType,
    file_extension: ext,
    is_pdf: isPdf,
    is_docx: isDocx,
    document_supported: isPdf || isDocx
  },
  binary
}];

const ctx = $('Detect document type').first().json;
const fileId = $json.id || $json.file_id || '';

return [{
  json: {
    ...ctx,
    openai_file_id: fileId,
    openai_body: {
      model: 'gpt-4o-mini',
      input: [
        {
          role: 'user',
          content: [
            {
              type: 'input_file',
              file_id: fileId
            },
            {
              type: 'input_text',
              text: 'Извлеки весь читаемый текст из файла резюме. Верни только сам текст резюме без комментариев, без Markdown и без JSON. Если текст не удалось извлечь, верни пустую строку.'
            }
          ]
        }
      ],
      temperature: 0
    }
  }
}];

const ctx = $('Prepare OpenAI Body: Extract document text').first().json;

function collectTextFromResponsesApi(j) {
  if (typeof j.output_text === 'string') return j.output_text;
  if (typeof j.text === 'string') return j.text;
  if (typeof j.content === 'string') return j.content;
  if (Array.isArray(j.output)) {
    const chunks = [];
    for (const out of j.output) {
      if (Array.isArray(out.content)) {
        for (const c of out.content) {
          if (typeof c.text === 'string') chunks.push(c.text);
          if (typeof c.output_text === 'string') chunks.push(c.output_text);
        }
      }
    }
    return chunks.join('\n').trim();
  }
  return '';
}

const text = collectTextFromResponsesApi($json);

return [{
  json: {
    ...ctx,
    input_type: 'document',
    text: String(text).trim(),
    normalized_text: String(text).trim(),
    extraction_provider: 'openai',
    extraction_status: String(text).trim() ? 'success' : 'empty'
  }
}];

const ctx = $('Build context after intake insert').first().json || {};
const err = $json.error || $json;
const technicalMessage = err.message || err.description || err.error || 'Document text extraction failed or returned empty text';

return [{
  json: {
    ...ctx,
    error_stage: 'intake',
    error_type: 'document_extract_error',
    error_message: String(technicalMessage || 'Document text extraction failed or returned empty text'),
    error_recoverable: true,
    response_channel: 'telegram',
    response_recipient: ctx.chat_id ? String(ctx.chat_id) : null,
    response_message_type: 'document_error',
    response_subject: null,
    response_body:
`⚠️ Не удалось извлечь текст из файла

Попробуйте:
• отправить PDF/DOCX с читаемым текстом
• отправить резюме текстом
• сделать фото резюме`
  }
}];

const ctx = $('Build context after intake insert').first().json;
const fileId = $json.id || $json.file_id || '';

return [{
  json: {
    ...ctx,
    input_type: 'image',
    openai_image_file_id: fileId,
    openai_body: {
      model: 'gpt-4o-mini',
      input: [
        {
          role: 'user',
          content: [
            {
              type: 'input_text',
              text: 'Извлеки весь читаемый текст с изображения резюме или анкеты кандидата. Верни только извлечённый текст без комментариев, без Markdown и без JSON.'
            },
            {
              type: 'input_image',
              file_id: fileId
            }
          ]
        }
      ],
      temperature: 0
    }
  }
}];

const ctx = $('Prepare OpenAI Body: OCR image').first().json;

function extractText(j) {
  if (typeof j.output_text === 'string' && j.output_text.trim()) {
    return j.output_text.trim();
  }

  const output = Array.isArray(j.output) ? j.output : [];
  const chunks = [];

  for (const item of output) {
    const content = Array.isArray(item.content) ? item.content : [];

    for (const part of content) {
      if (typeof part.text === 'string') {
        chunks.push(part.text);
      }

      if (typeof part.output_text === 'string') {
        chunks.push(part.output_text);
      }
    }
  }

  return chunks.join('\n').trim();
}

const text = extractText($json);

return [{
  json: {
    ...ctx,
    text: text,
    normalized_text: text,
    extraction_provider: 'openai',
    extraction_type: 'ocr_image',
    extraction_status: text ? 'success' : 'empty'
  }
}];

const ctx = $('Build context after intake insert').first().json || {};
const err = $json.error || $json;
const technicalMessage = err.message || err.description || err.error || 'Image OCR failed or returned empty text';

return [{
  json: {
    ...ctx,
    error_stage: 'intake',
    error_type: 'ocr_error',
    error_message: String(technicalMessage || 'Image OCR failed or returned empty text'),
    error_recoverable: true,
    response_channel: 'telegram',
    response_recipient: ctx.chat_id ? String(ctx.chat_id) : null,
    response_message_type: 'image_ocr_error',
    response_subject: null,
    response_body:
`⚠️ Не удалось прочитать текст с изображения

Попробуйте:
• сделать фото без бликов
• приблизить текст
• отправить PDF/DOCX или текст`
  }
}];

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: String($json.chat_id),
    response_message_type: 'apply',
    response_subject: null,
    response_body:
`📩 Отклик принят!

Мы передали вашу кандидатуру специалисту.
В ближайшее время с вами свяжутся.`
  }
}];

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: String($json.chat_id),
    response_message_type: 'next',
    response_subject: null,
    response_body:
`🔄 Пока доступна только лучшая вакансия.

Функция просмотра альтернативных вакансий будет добавлена следующим шагом.
Сейчас вы можете отправить другое резюме.`
  }
}];

return [{
  json: {
    ...$json,
    response_channel: 'telegram',
    response_recipient: String($json.chat_id),
    response_message_type: 'video_request',
    response_subject: null,
    response_body:
`🎬 Запрос на генерацию видео принят.

Видео создаётся отдельно и может занять несколько минут.
Я отправлю его сюда, когда оно будет готово.`
  }
}];
